#include<bits/stdc++.h>
using namespace std;
int main(){
    int a,b,c,d,cb,cc,cd;
    cin>>a>>b>>c>>d;
    cb=b-a;
    cc=c-a;
    cd=d-a;
    if(abs(cb)<abs(cc)&&abs(cb)<abs(cd)){
        cout<<b;
    }else if(abs(cc)<abs(cb)&&abs(cc)<abs(cd)){
        cout<<c;
    }else if(abs(cd)<abs(cb)&&abs(cd)<abs(cc)){
        cout<<d;
    }else{
        if(abs(cb)==abs(cc)){
            if(cb<cc){
                cout<<b;
            }else{
                cout<<c;
            }
        }if(abs(cb)==abs(cd)){
            if(cb<cd){
                cout<<b;
            }else{
                cout<<d;
            }
        }if(abs(cd)==abs(cc)){
            if(cd<cc){
                cout<<d;
            }else{
                cout<<c;
            }
        }
    }
    return 0;
}
